const isRegisteredLessThan12Months = () => {
    const currentDate = new Date();
    let borrowerRegistratrionDate;

    for (let counterparty of BusinessObject?.counterparties) {
        if (counterparty.roles.isBorrower) {
            borrowerRegistratrionDate = counterparty.counterpartyType.registrationDate;
            const loanDate = new Date(borrowerRegistratrionDate);
            const timeDifference = currentDate.getTime() - loanDate.getTime();
            const monthsPassed = Math.ceil(timeDifference / (1000 * 60 * 60 * 24 * 30));
            if (monthsPassed <= 12) {
                return true;
            }
        }
    }
    return false;
};
isRegisteredLessThan12Months();

