// Функция, принимающая объект BusinessObject и выполняющая замену BIC
function replaceBics(BusinessObject) {
    // Перебираем всех контрагентов
    for (let counterparty of BusinessObject.counterparties) {
        // Перебираем все банковские счета текущего контрагента
        for (let account of counterparty.bankAccounts) {
            // Извлекаем текущий BIC-код
            let bik = account.bik;

            // Проверка на пустоту BIC перед операциями
            if (typeof bik === 'string' && bik.trim().length > 0) {
                // Блок switch для замещения BIC по условиям
                switch(bik) {
                    case "048860630":
                        account.bik = "048073601";
                        break;
                    case "042406608":
                        account.bik = "047003608";
                        break;
                    case "043469623":
                        account.bik = "042007681";
                        break;
                    case "044959698":
                        account.bik = "041117601";
                        break;
                    case "043735650":
                        account.bik = "041806647";
                        break;
                    case "048405602":
                        account.bik = "045209673";
                        break;
                    default:
                        break; // Оставляем bik без изменений, если не попали под правила
                }
            }
        }
    }
}
replaceBics(BusinessObject);

