function setStatusNotForSBBOL() {
    const counterparites = BusinessObject.counterparties ?? [];

    for (const counterparty of counterparites) {
        if (counterparty?.roles?.isBorrower) {
            const docs = counterparty.documents ?? [];

            for (const doc of docs) {
                if ((doc?.type === "ProfAssertion"  || doc?.type === "RVPSDisposition")
                && doc?.status === "RECEIVED"  ) {
                    doc.status = "NOT_FOR_SBBOL";
                }
            }
        }
    }
}
setStatusNotForSBBOL();

for (let creditCondition of BusinessObject.creditConditions) {
