}

function setIsNonAcceptanceTrue(BusinessObject) {
   for (let i = 0; i < BusinessObject.counterparties.length; i++) {
        let counterparty = BusinessObject.counterparties[i];

        // Проверяем, является ли контрагент заемщиком
        if (counterparty.roles.isBorrower) {            
            // Перебор банковских счетов контрагента
            for (let j = 0; j < counterparty.bankAccounts.length; j++) {
                let account = counterparty.bankAccounts[j];

                // Сначала проверяем наличие объекта IsAccount
                if (account.isAccount && account.isAccount.isOpen) {

                    // Проверяем валюту и тип счета
                    if (
                        ['RUB', 'USD', 'EUR', 'CNY'].indexOf(account.currency) >= 0 &&
                        (account.accountType === '01' || account.accountType === '08')
                        && account?.source != 'Risks'
                    ) {
                        // Присваиваем isNonAcceptance в true
                        account.isAccount.isNonAcceptance = true;
                        if(account.isAccount.isSbrfAccount) {
                            account.paymentType = 'URGENT_OVERDUE';
                        } else {
                            account.paymentType = 'OVERDUE';
                        }
                    }
                }
            }
        }
    }
}
setIsNonAcceptanceTrue(BusinessObject);
